import '../css/about.css';
import React from 'react';
import {StaticImage} from 'gatsby-plugin-image';

const About = () => {
    return (
        <div id="about">
            <svg className="sep" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1921 154.5"><path class="cls-1" d="M0,926s179,0,414.5,94.25c329.82,132,601.5-17.14,904.5,18.32,367.92,43,545.5-.81,601.5-63.08v105H-.5Z" transform="translate(0.5 -926)"/></svg>    
        <div>
        <div className="bg-blue-600 text-white w-full pt-10 pb-20 pr-20 pl-20">
            <div className="text-center pb-6 pt-2">
                <span className="title text-4xl text-white">Hi, I'm Jesus</span>
            </div>
            <div className="text-center sm:pl-5 sm:pr-5 md:pl-32 md:pr-32 lg:px-52">
                <p className="title-content text-white dark:text-gray-200">I am a web designer and developer, with more than 2 years of experience, I have worked on some projects remotely and in small companies editing templates, designing websites and doing backend, I am very passionate about code and design.</p>
            </div>
        </div>

        
        <div className="lg:pl-48 lg:pr-48 md:pr-10 md:pl-10 sm:pl-10 sm:pr-10 text-center flex flex-wrap absolute -mt-16 card-container">

                <div className="lg:w-1/3 p-12 md:w-full sm:w-full bg-white dark:bg-gray-800 rounded-large md:rounded-sm lg:rounded-l-large lg:border-r dark:border-gray-700 mb-10 shadow-md lg:shadow-l">
                    <div className="p-10 h-42 m-auto">
                        <StaticImage className="w-32 m-auto" src="../images/s1.svg" alt="services" />
                    </div>
                    <span className="title text-blue-600 dark:text-gray-200">Front End</span>
                    <p className="p-5 text-gray-500 dark:text-gray-400 h-44">I transform mockups to a static or dynamic website, depending on your needs, always prioritizing mobile design and making use of new technologies and frameworks.</p>
                    <span className="text-blue-600 dark:text-gray-400 subtitle">Tools:</span><br/><br/>
                    <span className="text-gray-500 dark:text-gray-400">HTML5</span><br/>
                    <span className="text-gray-500 dark:text-gray-400">Javascript / React / Jquery</span><br/>
                    <span className="text-gray-500 dark:text-gray-400">Pure CSS / Bootstrap / Tailwind</span><br/>
                </div>

                <div className="lg:w-1/3 p-12 md:w-full sm:w-full bg-white dark:bg-gray-800 rounded-large md:rounded-sm lg:rounded-none mb-10 shadow-md lg:shadow-c">
                <div className="p-10 h-42 m-auto">
                <StaticImage className="w-32 m-auto" src="../images/s2.svg" alt="services" />
                    </div>
                    <span className="title text-blue-600 dark:text-gray-200">Back End</span>
                    <p className="p-5 text-gray-500 dark:text-gray-300 h-44">I can help you with the development of a more complex and extended site, on the server side, consuming APIs or modules and database management.</p>
                    <span className="text-blue-600 dark:text-gray-300 subtitle">Languages:</span><br/><br/>
                    <span className="text-gray-500 dark:text-gray-300">SQL</span><br/>
                    <span className="text-gray-500 dark:text-gray-300">C#</span><br/>
                    <span className="text-gray-500 dark:text-gray-300">PHP</span><br/>  
                </div>

                <div className="lg:w-1/3 p-12 md:w-full sm:w-full bg-white dark:bg-gray-800 rounded-large md:rounded-sm lg:rounded-r-large lg:border-l dark:border-gray-700 mb-10 shadow-md lg:shadow-r">
                    <div className="p-10 h-42 m-auto">
                    <StaticImage className="w-32 m-auto" src="../images/s3.svg" alt="services" />
                    </div>
                    <span className="title text-blue-600 dark:text-gray-200">Design</span>
                    <p className="p-5 text-gray-500 dark:text-gray-300 h-44">I can design mockups, logos and illustrations for your website, looking for cleanliness and clarity, focusing on minimalist design and usability.</p>
                    <span className="text-blue-600 dark:text-gray-300 subtitle">Tools:</span><br/><br/>
                    <span className="text-gray-500 dark:text-gray-300">Adobe Xd</span><br/>
                    <span className="text-gray-500 dark:text-gray-300">Adobe Illustrator</span><br/>
                    <span className="text-gray-500 dark:text-gray-300">Adobe Photoshop</span><br/>   
                </div>
        </div>
        <div className="separator">
        </div>
    </div>
    </div>
    )
}

export default About;